local POW2 = { [0]=1, 2, 4, 8, 16, 32, 64, 128 }

local function log(msg)
  if log_fn then pcall(log_fn, "[pokemon_platinum] " .. tostring(msg)) end
end

-- ── Memory API (resolved at init; 2-arg domain form + current-domain fallback) ─
local function resolve_memory_api()
  if not memory then return false end
  mem.read_u8  = memory.read_u8     or memory.readbyte
  mem.read_u16 = memory.read_u16_le or memory.readword
  mem.read_u32 = memory.read_u32_le or memory.readdword
  mem.read_rng = memory.read_bytes_as_array or memory.readbyterange
  return mem.read_u8 ~= nil and mem.read_u32 ~= nil
end

local function rd(fn, addr, domain)
  if not fn then return nil end
  local ok, v = pcall(fn, addr, domain)
  if ok and type(v) == "number" then return v end
  ok, v = pcall(fn, addr)                       -- older API: current domain
  if ok and type(v) == "number" then return v end
  return nil
end

local function read_u8(a, d)  return rd(mem.read_u8,  a, d) end
local function read_u32(a, d) return rd(mem.read_u32, a, d) end

-- Read `len` bytes → 1-based array (or nil). Bulk API first (both 0- and 1-based
-- variants normalized), per-byte fallback.
local function read_range(addr, len, domain)
  if mem.read_rng then
    local ok, t = pcall(mem.read_rng, addr, len, domain)
    if ok and type(t) == "table" then
      if t[0] ~= nil then
        local out = {}
        for i = 0, len - 1 do out[i + 1] = t[i] end
        return out
      end
      if t[1] ~= nil or len == 0 then return t end
    end
  end
  local out = {}
  for i = 0, len - 1 do
    local v = read_u8(addr + i, domain)
    if not v then return nil end
    out[i + 1] = v
  end
  return out
end

-- ── ROM identity: mirror client.validate_rom (NDS header game title @ ROM 0) ───
-- Vanilla = "POKEMON PL"; AP-patched = "PLAP <hex version>" (e.g. "PLAP 1").
local function read_rom_title()
  local b = read_range(0, 12, ROM)
  if not b then return nil end
  local out = {}
  for i = 1, #b do
    local c = b[i]
    if c and c ~= 0 then out[#out + 1] = string.char(c) end
  end
  return table.concat(out)
end

local function rom_is_ap()
  if rom_ok ~= nil then return rom_ok end
  local title = read_rom_title()
  if title == nil then return false end          -- ROM domain not ready; retry
  if title == "POKEMON PL" then
    rom_ok = false
    why_disabled = "unpatched vanilla Pokémon Platinum ROM (apply the seed's " ..
                   ".applatinum patch) — checks/goal DISABLED"
    log(why_disabled)
    return false
  end
  if title:sub(1, 5) == "PLAP " then
    local ver = tonumber((title:sub(6):gsub("%s+$", "")), 16)
    if ver == AP_VERSION then
      rom_ok = true
      log("AP ROM verified: '" .. title .. "'")
      return true
    end
    rom_ok = false
    why_disabled = "AP ROM version '" .. title .. "' != supported version " ..
                   AP_VERSION .. " — checks/goal DISABLED"
    log(why_disabled)
    return false
  end
  rom_ok = false
  why_disabled = "ROM title '" .. tostring(title) ..
                 "' is not a Pokémon Platinum AP ROM — module disabled"
  log(why_disabled)
  return false
end

-- ── AP struct discovery + validation (client.get_struct_addr / header guard) ──
local function header_ok(addr)
  -- 16-byte header: " AP "×3 + version (4 LE).
  local b = read_range(addr, 16, SYS)
  if not b then return false end
  for i = 1, 12 do
    if b[i] ~= string.byte(AP_MAGIC, ((i - 1) % 4) + 1) then return false end
  end
  -- version little-endian u32
  if b[13] ~= (AP_VERSION % 256) then return false end
  if b[14] ~= 0 or b[15] ~= 0 or b[16] ~= 0 then return false end
  return true
end

local function discover_struct()
  local addr = read_u32(AP_STRUCT_PTR, SYS)
  if not addr then return false end
  if addr <= AP_STRUCT_MIN or addr >= AP_STRUCT_PTR then return false end
  if not header_ok(addr) then return false end
  ap_struct = addr
  log(string.format("AP struct found at 0x%X", addr))
  return true
end

-- ── Multiworld context ────────────────────────────────────────────────────────
local function load_locations(ids)
  if type(ids) ~= "table" then return end
  server_locations = {}
  local n = 0
  for _, id in ipairs(ids) do
    local v = tonumber(id)
    if v then server_locations[v] = true; n = n + 1 end
  end
  log("server location set: " .. n .. " ids")
end

local function wanted(ap_id)
  if server_locations == nil then return true end
  return server_locations[ap_id] == true
end

-- op: 0=eq 1=ne 2=lt 3=le 4=gt 5=ge
local function cmp(a, op, b)
  if     op == 0 then return a == b
  elseif op == 1 then return a ~= b
  elseif op == 2 then return a <  b
  elseif op == 3 then return a <= b
  elseif op == 4 then return a >  b
  else                return a >= b end
end

-- ── Module contract ───────────────────────────────────────────────────────────
function M.init(ctx)
  if ctx and type(ctx.log) == "function" then log_fn = ctx.log end
  if not ADDRESSES_VERIFIED then
    log("address map not verified — module idle"); return
  end
  if not resolve_memory_api() then
    why_disabled = "BizHawk memory API unavailable"; log(why_disabled)
    ADDRESSES_VERIFIED = false; return
  end
  local cfg = (ctx and ctx.config) or {}
  load_locations(cfg.locations)
  for _ in pairs(FLAG_LOC) do n_flag = n_flag + 1 end
  for _ in pairs(ONCE_LOC) do n_once = n_once + 1 end
  for _ in pairs(VAR_LOC)  do n_var  = n_var  + 1 end
  log(string.format("ready: %d flag + %d once + %d var location checks, goal flag %d",
                    n_flag, n_once, n_var, GOAL_FLAG))
end

-- bit test in a 1-based byte array: flag_id // 8 → byte (1-based), id % 8 → bit.
local function flag_set(arr, flag_id)
  local byte = math.floor(flag_id / 8) + 1
  local v = arr[byte]
  if not v then return false end
  return (v % POW2[(flag_id % 8) + 1]) >= POW2[flag_id % 8]
end

function M.poll()
  local out = {}
  if not ADDRESSES_VERIFIED then return out end
  if not rom_is_ap() then return out end

  -- Discover/re-validate the AP struct (cleared if it moved).
  if ap_struct == 0 then
    discover_struct()
    return out
  end
  if not header_ok(ap_struct) then ap_struct = 0; return out end

  local savedata_ptr = read_u32(ap_struct + SAVEDATA_PTR_OFF, SYS)
  if not savedata_ptr or savedata_ptr <= AP_STRUCT_MIN then return out end

  -- Bulk reads (the apworld's two guarded_read blocks).
  local vf   = read_range(savedata_ptr + VARS_FLAGS_OFF, VARS_FLAGS_SIZE, SYS)
  local once = vf and read_range(savedata_ptr + AP_SAVE_OFF + ONCE_OFF_IN_AP,
                                 math.floor((ONCE_COUNT + 7) / 8), SYS)
  if not vf or not once then return out end

  -- guarded_read stand-in: discard if the struct header changed or the
  -- savedata pointer moved while we were reading.
  if not header_ok(ap_struct)
     or read_u32(ap_struct + SAVEDATA_PTR_OFF, SYS) ~= savedata_ptr then
    return out
  end

  -- vars (u16 LE) and flags (bit array) sub-views into vars_flags. flags index k
  -- corresponds to vf[FLAGS_OFF_IN_VF + k + 1]; var u16 #i is at vf bytes
  -- VARS_OFF_IN_VF + i*2 (+1/+2 for 1-based).
  local function flags_byte(idx)   return vf[FLAGS_OFF_IN_VF + idx + 1] end
  local function var_u16(var_idx)
    local off = VARS_OFF_IN_VF + var_idx * 2
    local lo, hi = vf[off + 1], vf[off + 2]
    if not lo or not hi then return nil end
    return lo + hi * 256
  end

  local function flag_id_set(flag_id)
    if flag_id <= 0 then return false end        -- client guards id>0
    local v = flags_byte(math.floor(flag_id / 8))
    if not v then return false end
    return (v % POW2[(flag_id % 8) + 1]) >= POW2[flag_id % 8]
  end
  local function once_id_set(once_id)
    return flag_set(once, once_id)
  end

  -- FlagCheck locations.
  for raw, flag_id in pairs(FLAG_LOC) do
    if not reported[raw] and wanted(raw) and flag_id_set(flag_id) then
      reported[raw] = true
      out[#out + 1] = raw
    end
  end
  -- OnceCheck locations.
  for raw, once_id in pairs(ONCE_LOC) do
    if not reported[raw] and wanted(raw) and once_id_set(once_id) then
      reported[raw] = true
      out[#out + 1] = raw
    end
  end
  -- VarCheck locations.
  for raw, q in pairs(VAR_LOC) do
    if not reported[raw] and wanted(raw) then
      local v = var_u16(q[1])
      if v ~= nil and cmp(v, q[3], q[2]) then
        reported[raw] = true
        out[#out + 1] = raw
      end
    end
  end

  -- Goal: beat_cynthia flag.
  if not goal_reached and flag_id_set(GOAL_FLAG) then
    goal_reached = true
    log("goal flag " .. GOAL_FLAG .. " (beat_cynthia) set — goal complete")
  end

  return out
end

function M.is_goal_complete()
  return goal_reached
end

-- Remote multiworld items: see the file header. items_handling = 0b001 (the
-- default, RemoteItems off) means the server sends only THIS slot's own items and
-- the patched game grants its locally-found items itself, so solo play and check
-- reporting work fully. Applying REMOTE items is the client's guarded ring-buffer
-- write into the AP struct's remote_item_queue; that is deferred until it can be
-- confirmed in-emulator, rather than shipped unverified. No-op (never a wrong
-- write) until then.
function M.receive_item(item_id, meta)
  -- intentionally empty (documented)
end

return M
